fn gcd(a: Int, b: Int) -> Int:
    if b == 0: return a
    return gcd(b, a % b)

fn gcd_lcm(a: Int, b: Int) -> Tuple[Int, Int]:
    var g = gcd(a, b)
    return (g, a // g * b)
